import React from 'react'

import loadable from '@loadable/component'

const Icon2 = loadable(() => import('./Icons'))



export default function StarsRating(props) {
  let rate = props.rate;
  let size = props.size || 14;

  
  return (
      <div className="COzjKb DX0ugf ApBhXe">
        {[1,2,3,4,5].map(st=>{
          return <Icon2
            key={st+"_start_rating"}
            name={rate>=st?"star":rate>(st-1)?"star_half_full":"star_outline"}
            color={"rgb(249, 171, 0)"}
            size={size}
          />
        })}
      </div>
    )
}
